const STATUS={PENDING:{label:"Pending",cls:"bg-amber-100 text-amber-700"},IN_PROCESS:{label:"In Process",cls:"bg-blue-100 text-blue-700"},READY:{label:"Ready",cls:"bg-emerald-100 text-emerald-700"},DELIVERED:{label:"Delivered",cls:"bg-gray-100 text-gray-500"}};
